    func testErrorHandlingInvalidSyntax() throws {
        // Parsing invalid syntax should produce a tree with error nodes.
        let configObj = try TreeSitterLanguagePack.processConfigFromJson("{\"language\":\"javascript\"}")
        let result = try TreeSitterLanguagePack.process(source: "function function function @@@ %%%", config: configObj)
    }

    func testErrorHandlingUnknownLanguage() throws {
        // Loading a nonexistent language should produce an error.
        do {
            let configObj = try TreeSitterLanguagePack.processConfigFromJson("{\"language\":\"nonexistent_xyz\"}")
            _ = try TreeSitterLanguagePack.process(source: "", config: configObj)
            XCTFail("expected to throw")
        } catch {
            // success
        }
    }

    func testErrorProcessEmptySource() throws {
        // Process empty source code succeeds with zero metrics
        let configObj = try TreeSitterLanguagePack.processConfigFromJson("{\"language\":\"python\"}")
        let result = try TreeSitterLanguagePack.process(source: "", config: configObj)
        XCTAssertEqual(result.metrics().totalLines(), 0)
    }

    func testParseEmptyLanguage() throws {
        // process() returns error with empty language name
        do {
            let configObj = try TreeSitterLanguagePack.processConfigFromJson("{\"language\":\"\"}")
            _ = try TreeSitterLanguagePack.process(source: "x = 1", config: configObj)
            XCTFail("expected to throw")
        } catch {
            // success
        }
    }

    func testProcessUnknownLanguage() throws {
        // process() returns error when config language is unknown
        do {
            let configObj = try TreeSitterLanguagePack.processConfigFromJson("{\"language\":\"nonexistent_xyz\"}")
            _ = try TreeSitterLanguagePack.process(source: "x = 1", config: configObj)
            XCTFail("expected to throw")
        } catch {
            // success
        }
    }

}
